#!/usr/bin/env bash
# Car Wash — deterministic stem mixer. Installs locally. No AI. Nothing uploaded.
set -e
DEST="$HOME/.carwash"; BIN="$HOME/.local/bin"
mkdir -p "$DEST" "$BIN"
PY="$(command -v python3 || command -v python)"
[ -z "$PY" ] && { echo "need python3"; exit 1; }
echo "unpacking the Forge -> $DEST"
"$PY" - "$DEST" <<'PYEOF'
import base64,io,sys,tarfile
B64=""
tarfile.open(fileobj=io.BytesIO(base64.b64decode(B64)),mode="r:gz").extractall(sys.argv[1])
PYEOF
"$PY" -c "import numpy,scipy,soundfile,pyloudnorm" 2>/dev/null && echo "deps present" \
  || { echo "installing deps (numpy scipy soundfile pyloudnorm)"; \
       "$PY" -m pip install --quiet --user numpy scipy soundfile pyloudnorm 2>/dev/null \
       || "$PY" -m pip install --quiet --break-system-packages numpy scipy soundfile pyloudnorm; }
cat > "$BIN/carwash" <<EOF
#!/usr/bin/env bash
exec "$PY" "$DEST/carwash.py" "\$@"
EOF
chmod +x "$BIN/carwash"
echo ""
echo "installed. opening Car Wash — type 'yes' then 'mix'."
echo "(everything runs here; your audio never leaves this machine)"
exec "$PY" "$DEST/carwash.py" go
